var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"여기는 고치 관측소!","JPN":"こちら繭観測所！","ENG":"This is the cocoon observatory!","TWN":"這裡是繭觀測站！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L4_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"아무래도 관측소에서 관리하고 있는 고치에서 문제가 발생한 것 같아!","JPN":"どうやら観測所で管理している繭に問題が発生したみたいなんだ！","ENG":"I think there's a problem with one of the cocoons at the observatory!","TWN":"觀測站裡的繭似乎出現問題了！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"전송한 좌표의 네피림 고치에서 고치 특유의 파장이 관측되지 않고 있어!","JPN":"送った座標のネフィリムの繭から繭特有の波長が観測されない状況だ！","ENG":"I'm not seeing the unique wavelengths of a Nephil cocoon at the coordinates I just sent you!","TWN":"這個傳送座標下的諾菲力繭，沒有觀測到其特有的波長！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"물론, 고치 주변에 설치해둔 침식파 송신기가 고장을 일으킨 걸 수도 있지만…… ","JPN":"もちろん、繭周辺に設置した侵食波送信機が故障しただけかもしれないけど…… ","ENG":"Of course, it could just be a malfunction of the Corruption ray transmitter that's been set up near the cocoons...","TWN":"當然，不排除繭周圍設置的侵蝕波發射器出現了故障……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"어쨌든 직접 가서 확인이 필요해!","JPN":"とにかく、行って確認する必要があるんだ！","ENG":"Anyway, someone needs to go check it out!","TWN":"不管怎樣，需要有人親自去確認一下！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"뭐야, 긴급 사이렌까지 울려 놓고 또 호들갑이야?","JPN":"何よ、緊急サイレンまで鳴らしておいて、またフライングなの？","ENG":"Huh? Why are you making a fuss even after ringing the emergency alarm?","TWN":"好了好了，我們都聽到警報了，別大驚小怪的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"양치기 소년도 아니고 자꾸 이러면 곤란해, 엉터리 박사?","JPN":"オオカミ少年じゃあるまいし、何度も困るわよ、へぼ博士！","ENG":"What are you, the boy who cried wolf? This isn't going to fly, Dr. Quack.","TWN":"又不是在模仿“狼來了”，你老是這樣很令人頭疼呢，笨蛋博士？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"시끄러워, 이 분홍 꼬맹아!","JPN":"うるさい、このピンク頭！","ENG":"Shut up, you pink child!","TWN":"吵死了，你這個粉紅小屁孩！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"고치랑 관련된 일은 사소한 거라도 무조건 긴급으로 보고하라는 소령의 명령이야!","JPN":"繭に関わる事項は些細なことまですべて緊急報告しろっていうのが少佐の命令なんだ！","ENG":"It was Major's orders to make anything related to cocoons an emergency no matter what!","TWN":"與繭相關的事情，有任何風吹草動都必須立刻上報，這是少校的命令！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"맞습니다. 방심하는 것보단 이쪽이 낫죠.","JPN":"はい。油断するよりはこっちの方がマシです。","ENG":"He's right. It's better to be safe than sorry.","TWN":"沒錯。比起掉以輕心，我們更應該時刻警惕著。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하암~ 이른 시간부터 부지런도 하셔라.","JPN":"ふぁ～早朝から騒がしいですね。","ENG":"*Yawn* My, you all seem to be very busy this early in the morning.","TWN":"哈啊～一大早的就這麼認真。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"저는 하루에 10시간을 자야 컨디션을 유지할 수 있어서요.","JPN":"私は一日に10時間は寝ておかないとベストコンディションを保てないんですよ。","ENG":"But I need my 10 hours of sleep to maintain my performance.","TWN":"我一天得睡夠10小時才行。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"좌표에 도착하면 깨워주세요.","JPN":"座標に着いたら起こしてください。","ENG":"Wake me up when we arrive at the coordinates.","TWN":"記得到了之後再叫醒我喔。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"네~ 네~ 어련들 하시겠어. 얼렁 갔다 오자고.","JPN":"はいはい～そうでしょうとも。とっとと終わらすわよ。","ENG":"Yeah, yeah, whatever. Let's get this done already.","TWN":"好～～好～知道了，我們快去快回。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"좌표 계산 뭐, 대충 완료. 공간 도약 시퀸스 준비.","JPN":"座標計算、まぁだいたい完了。空間跳躍シークエンスを準備。","ENG":"Coordinates calculations, meh, it's good enough. Preparing a space jump sequence.","TWN":"座標計算，大致上沒問題。空間跳躍程式準備。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"3…… 2…… 1……","JPN":"3……2……1……","ENG":"In 3, 2, 1...","TWN":"3……2……1……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"공간 도약 스타트!","JPN":"空間跳躍、開始！","ENG":"Initiating the space jump!","TWN":"啟動！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L30_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"공간 도약 완료.","JPN":"空間跳躍、完了。","ENG":"Space jump complete.","TWN":"空間跳躍結束。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"전송된 해당 좌표 근처에 도착했어.","JPN":"送られてきた座標周辺に着いたわ。","ENG":"We've arrived near the corresponding coordinates.","TWN":"已到達傳送的座標附近。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"얼레? 근데 뭔가 침식체 녀석들의 움직임이 이상한데?","JPN":"あれ？　でも何だか侵食体の連中の動きがおかしいわね？","ENG":"Huh? But the movement of those C.O.s are kinda weird.","TWN":"喔？這裡的侵蝕體行為有些奇怪呢？"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"고치가 있는 곳으로부터 침식체가 무리를 지어 어디론가 이동하고 있어.","JPN":"繭のある場所から侵食体が群れを成してどこかに移動してる。","ENG":"The C.O.s are moving away in hordes from where the cocoon is.","TWN":"他們正從繭所在的地方，成群結隊地往某個地方移動。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"이쪽 방향으로 온다!","JPN":"こっちに来るわ！","ENG":"They're coming this way!","TWN":"往這邊來了！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"어차피 고치를 육안으로 관측하기 위해서는 침식체 무리를 정리해야 해요.","JPN":"どのみち繭を肉眼で確認するには侵食体の群れを片付けないといけません。","ENG":"If we want to inspect the cocoon with our own eyes, we still have to clear all the C.O.s.","TWN":"來得正好，反正檢查繭之前也要先清理這些侵蝕體群。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"전방위 폭격으로 침식체 무리를 소각!","JPN":"まず全方位爆撃で侵食体の群れを焼却！","ENG":"Incinerate the horde of C.O.s with bombs!","TWN":"首先對侵蝕體群發動全方位轟炸！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이후, 강하해서 잔존 침식체 무리를 섬멸합니다!","JPN":"その後降下し、残った侵食体の群れを殲滅します！","ENG":"Afterward, we deploy down to annihilate the remaining!","TWN":"之後，由我們登陸殲滅殘存的侵蝕體！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"전장 소각 개시!","JPN":"戦場焼却開始！","ENG":"Incinerating the battlefield!","TWN":"開始執行！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};